arguments.file_text:
namespace sv_d5516d5ff6054d99b91445a9c3644c78.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@page "/chat"
@using sv_d5516d5ff6054d99b91445a9c3644c78.Services
@inject IChatService ChatService
@inject IJSRuntime JS
@rendermode InteractiveServer

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    @* ── Left sidebar: channel list ── *@
    <aside class="chat-sidebar">
        <div class="sidebar-header">
            <h3>Channels</h3>
        </div>
        <ul class="channel-list">
            @foreach (var channel in channels)
            {
                <li class="channel-item @(channel.Id == activeChannelId ? "active" : "")"
                    @onclick="() => SelectChannelAsync(channel)">
                    <div class="channel-name"># @channel.Name</div>
                    <div class="channel-desc">@TruncateDescription(channel.Description)</div>
                    @if (channel.UnreadCount > 0)
                    {
                        <span class="unread-badge">@channel.UnreadCount</span>
                    }
                </li>
            }
        </ul>
    </aside>

    @* ── Main message area ── *@
    <section class="chat-main @(threadOpen ? "thread-open" : "")">
        @if (activeChannel is not null)
        {
            <div class="main-header">
                <h2># @activeChannel.Name</h2>
                <span class="main-header-desc">@activeChannel.Description</span>
            </div>

            <div class="message-list" @ref="messageListRef" @onscroll="HandleScrollAsync">
                @if (isLoadingMore)
                {
                    <div class="loading-indicator">Loading older messages…</div>
                }
                @foreach (var msg in messages)
                {
                    <div class="message-row" @key="msg.Id">
                        <div class="message-bubble">
                            <div class="message-header">
                                <span class="msg-author">@msg.Author</span>
                                <span class="msg-time">@FormatRelativeTime(msg.SentAt)</span>
                            </div>
                            <div class="msg-content">@msg.Content</div>

                            @if (msg.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in msg.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(msg.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }

                            @{ var summary = threadSummaries.GetValueOrDefault(msg.Id); }
                            @if (summary is not null)
                            {
                                <button class="thread-link" @onclick="() => OpenThreadAsync(msg.Id)">
                                    @summary.ReplyCount @(summary.ReplyCount == 1 ? "reply" : "replies")
                                    — last @FormatRelativeTime(summary.LastReplyAt)
                                </button>
                            }

                            <div class="message-actions">
                                <button class="action-btn" title="Reply in thread"
                                        @onclick="() => OpenThreadAsync(msg.Id)">💬 Reply</button>
                                <button class="action-btn" title="Add reaction"
                                        @onclick="() => ToggleEmojiPicker(msg.Id)">😀 React</button>
                            </div>

                            @if (emojiPickerMessageId == msg.Id)
                            {
                                <div class="emoji-picker">
                                    @foreach (var emoji in commonEmojis)
                                    {
                                        <button class="emoji-option" @onclick="() => PickEmojiAsync(msg.Id, emoji)">
                                            @emoji
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Message #@activeChannel.Name"
                          @bind="newMessageText" @bind:event="oninput"
                          @onkeydown="HandleMainKeyDown" />
                <button class="send-btn" @onclick="SendMessageAsync" disabled="@string.IsNullOrWhiteSpace(newMessageText)">
                    Send
                </button>
            </div>
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </section>

    @* ── Right panel: thread view ── *@
    @if (threadOpen && threadRootMessage is not null)
    {
        <aside class="chat-thread-panel">
            <div class="thread-header">
                <h3>Thread</h3>
                <button class="close-thread-btn" @onclick="CloseThread">✕</button>
            </div>
            <div class="thread-root-quote">
                <span class="msg-author">@threadRootMessage.Author</span>
                <span class="msg-time">@FormatRelativeTime(threadRootMessage.SentAt)</span>
                <div class="msg-content">@threadRootMessage.Content</div>
            </div>

            <div class="thread-replies">
                @foreach (var reply in threadReplies)
                {
                    <div class="message-row" @key="reply.Id">
                        <div class="message-bubble">
                            <div class="message-header">
                                <span class="msg-author">@reply.Author</span>
                                <span class="msg-time">@FormatRelativeTime(reply.SentAt)</span>
                            </div>
                            <div class="msg-content">@reply.Content</div>

                            @if (reply.Reactions.Count > 0)
                            {
                                <div class="reaction-row">
                                    @foreach (var r in reply.Reactions)
                                    {
                                        <button class="reaction-badge" title="@string.Join(", ", r.Users)"
                                                @onclick="() => ReactAsync(reply.Id, r.Emoji)">
                                            @r.Emoji @r.Users.Count
                                        </button>
                                    }
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>

            <div class="message-input-area">
                <textarea class="message-input" rows="2" placeholder="Reply…"
                          @bind="threadReplyText" @bind:event="oninput"
                          @onkeydown="HandleThreadKeyDown" />
                <button class="send-btn" @onclick="SendThreadReplyAsync"
                        disabled="@string.IsNullOrWhiteSpace(threadReplyText)">
                    Reply
                </button>
            </div>
        </aside>
    }
</div>

@code {
    private const int PageSize = 30;
    private static readonly string[] commonEmojis = ["👍", "❤️", "😂", "🎉", "🔥", "👀"];

    // ── State ──
    private List<Channel> channels = [];
    private int activeChannelId;
    private Channel? activeChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private int messagesSkip;
    private bool hasMoreMessages = true;
    private bool isLoadingMore;

    private string newMessageText = string.Empty;
    private int? emojiPickerMessageId;

    // Thread panel
    private bool threadOpen;
    private int threadRootId;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];
    private string threadReplyText = string.Empty;

    private ElementReference messageListRef;

    // ── Lifecycle ──
    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
    }

    // ── Channel selection ──
    private async Task SelectChannelAsync(Channel channel)
    {
        if (channel.Id == activeChannelId) return;

        activeChannelId = channel.Id;
        activeChannel = channel;
        messages.Clear();
        threadSummaries.Clear();
        messagesSkip = 0;
        hasMoreMessages = true;
        emojiPickerMessageId = null;

        await LoadMessagesAsync();
        await ChatService.MarkChannelReadAsync(channel.Id);

        // Update unread count locally
        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
            activeChannel = channels[idx];
        }
    }

    private async Task LoadMessagesAsync()
    {
        var batch = await ChatService.GetMessagesAsync(activeChannelId, messagesSkip, PageSize);
        if (batch.Count < PageSize)
            hasMoreMessages = false;

        // Prepend older messages
        messages.InsertRange(0, batch);
        messagesSkip += batch.Count;

        BuildThreadSummaries();
    }

    private void BuildThreadSummaries()
    {
        // Group replies by their root message to build thread summaries
        var replies = messages.Where(m => m.ReplyToId.HasValue).ToList();
        var grouped = replies.GroupBy(m => m.ReplyToId!.Value);

        foreach (var g in grouped)
        {
            threadSummaries[g.Key] = new ThreadSummary(
                g.Key,
                g.Count(),
                g.Max(m => m.SentAt)
            );
        }
    }

    // ── Scroll-to-top pagination ──
    private async Task HandleScrollAsync()
    {
        if (!hasMoreMessages || isLoadingMore) return;

        var scrollTop = await JS.InvokeAsync<double>("eval", "document.querySelector('.message-list')?.scrollTop ?? 1");
        if (scrollTop < 50)
        {
            isLoadingMore = true;
            StateHasChanged();

            await LoadMessagesAsync();

            isLoadingMore = false;
            StateHasChanged();
        }
    }

    // ── Send message ──
    private async Task SendMessageAsync()
    {
        if (string.IsNullOrWhiteSpace(newMessageText) || activeChannel is null) return;

        var sent = await ChatService.SendMessageAsync(activeChannelId, newMessageText.Trim(), null);
        messages.Add(sent);
        newMessageText = string.Empty;

        await ScrollToBottomAsync();
    }

    private async Task HandleMainKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessageAsync();
        }
    }

    // ── Reactions ──
    private void ToggleEmojiPicker(int messageId)
    {
        emojiPickerMessageId = emojiPickerMessageId == messageId ? null : messageId;
    }

    private async Task PickEmojiAsync(int messageId, string emoji)
    {
        emojiPickerMessageId = null;
        await ReactAsync(messageId, emoji);
    }

    private async Task ReactAsync(int messageId, string emoji)
    {
        await ChatService.AddReactionAsync(messageId, emoji);

        // Optimistic update: add/increment the reaction locally
        var msg = messages.FirstOrDefault(m => m.Id == messageId)
                  ?? threadReplies.FirstOrDefault(m => m.Id == messageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(emoji, ["You"]));
            }
        }
    }

    // ── Thread panel ──
    private async Task OpenThreadAsync(int rootMessageId)
    {
        threadRootId = rootMessageId;
        threadRootMessage = messages.FirstOrDefault(m => m.Id == rootMessageId);
        threadReplies = await ChatService.GetThreadAsync(rootMessageId);
        threadReplyText = string.Empty;
        threadOpen = true;
    }

    private void CloseThread()
    {
        threadOpen = false;
        threadRootMessage = null;
        threadReplies.Clear();
        threadReplyText = string.Empty;
    }

    private async Task SendThreadReplyAsync()
    {
        if (string.IsNullOrWhiteSpace(threadReplyText) || threadRootMessage is null) return;

        var reply = await ChatService.SendMessageAsync(activeChannelId, threadReplyText.Trim(), threadRootId);
        threadReplies.Add(reply);
        messages.Add(reply);
        threadReplyText = string.Empty;

        BuildThreadSummaries();
    }

    private async Task HandleThreadKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendThreadReplyAsync();
        }
    }

    // ── Helpers ──
    private async Task ScrollToBottomAsync()
    {
        await JS.InvokeVoidAsync("eval",
            "setTimeout(() => { const el = document.querySelector('.message-list'); if(el) el.scrollTop = el.scrollHeight; }, 50)");
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();
        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
    }

    private static string TruncateDescription(string desc)
    {
        return desc.Length > 50 ? desc[..47] + "…" : desc;
    }
}

