    position: absolute;
    top: -4px;
    right: 8px;
    background: #1a1d21;
    border: 1px solid #3c3d40;
    border-radius: 6px;
    overflow: hidden;
    z-index: 10;
}

.message-bubble:hover .message-actions {
    display: flex;
}

.action-btn {
    background: none;
    border: none;
    color: #b4b5b7;
    font-size: 0.78rem;
    padding: 4px 10px;
    cursor: pointer;
    white-space: nowrap;
    transition: background 0.15s, color 0.15s;
}

.action-btn:hover {
    background: #2c2d30;
    color: #fff;
}

/* ── Emoji picker ── */
.emoji-picker {
    display: flex;
    gap: 2px;
    margin-top: 4px;
    background: #2c2d30;
    border: 1px solid #3c3d40;
    border-radius: 8px;
    padding: 4px 6px;
    width: fit-content;
}

.emoji-option {
    background: none;
    border: none;
    font-size: 1.2rem;
    cursor: pointer;
    padding: 2px 4px;
    border-radius: 4px;
    transition: background 0.15s;
}

.emoji-option:hover {
    background: #3a3d42;
}

/* ── Thread link ── */
.thread-link {
    background: none;
    border: none;
    color: #1d9bd1;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    display: block;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ── Message input ── */
.message-input-area {
    display: flex;
    align-items: flex-end;
    gap: 8px;
    padding: 10px 20px 14px;
    border-top: 1px solid #2c2d30;
    flex-shrink: 0;
}

.message-input {
    flex: 1;
    resize: none;
    background: #222529;
    border: 1px solid #3c3d40;
    border-radius: 8px;
    padding: 8px 12px;
    color: #d1d2d3;
    font-size: 0.9rem;
    font-family: inherit;
    outline: none;
    transition: border-color 0.15s;
}

.message-input:focus {
    border-color: #1d9bd1;
}

.send-btn {
    background: #007a5a;
    color: #fff;
    border: none;
    border-radius: 8px;
    padding: 8px 18px;
    font-weight: 600;
    font-size: 0.85rem;
    cursor: pointer;
    transition: background 0.15s;
    white-space: nowrap;
}

.send-btn:hover:not(:disabled) {
    background: #148567;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

/* ── Right thread panel ── */
.chat-thread-panel {
    width: 25%;
    min-width: 260px;
    background: #1a1d21;
    border-left: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.thread-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 12px 16px;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.thread-header h3 {
    margin: 0;
    font-size: 1rem;
    color: #fff;
}

.close-thread-btn {
    background: none;
    border: none;
    color: #b4b5b7;
    font-size: 1.1rem;
    cursor: pointer;
    padding: 2px 6px;
    border-radius: 4px;
    transition: background 0.15s;
}

.close-thread-btn:hover {
    background: #2c2d30;
    color: #fff;
}

.thread-root-quote {
    padding: 10px 16px;
    background: #222529;
    border-bottom: 1px solid #2c2d30;
    flex-shrink: 0;
}

.thread-replies {
    flex: 1;
    overflow-y: auto;
    padding: 8px 16px;
}

/* ── Scrollbar styling ── */
.message-list::-webkit-scrollbar,
.thread-replies::-webkit-scrollbar,
.channel-list::-webkit-scrollbar {
    width: 6px;
}

.message-list::-webkit-scrollbar-thumb,
.thread-replies::-webkit-scrollbar-thumb,
.channel-list::-webkit-scrollbar-thumb {
    background: #3c3d40;
    border-radius: 3px;
}

.message-list::-webkit-scrollbar-track,
.thread-replies::-webkit-scrollbar-track,
.channel-list::-webkit-scrollbar-track {
    background: transparent;
}
"}

