toolArgs.file_text:
/* ── Layout shell ── */
.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    background: #1a1d21;
    color: #d1d2d3;
}

/* ── Left sidebar ── */
.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #19171d;
    border-right: 1px solid #2c2d30;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid #2c2d30;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    color: #fff;
}

.channel-list {
    list-style: none;
    margin: 0;
    padding: 8px 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: #27242c;
}

.channel-item.active {
    background: #1164a3;
}

.channel-item.active .channel-name,
.channel-item.active .channel-desc {
    color: #fff;
}

.channel-name {
    font-weight: 600;
